def ipToCIDR(ip, n):
    def ipToInt(ip):
        ans = 0
        for x in ip.split('.'):
            ans = 256 * ans + int(x)
        return ans
    def intToIP(x):
        return "%s.%s.%s.%s" % (x >> 24, (x >> 16) % 256, (x >> 8) % 256, x % 256)
    start = ipToInt(ip)
    ans = []
    while n > 0:
        mask = max(33 - (start & -start).bit_length(), 33 - n.bit_length())
        ans.append(intToIP(start) + '/' + str(mask))
        start += 1 << (32 - mask)
        n -= 1 << (32 - mask)
    return ans

